public Dictionary<string, string> ParseXmlConfiguration(string xmlFilePath)
{
    Dictionary<string, string> configSettings = new Dictionary<string, string>();

    XmlDocument xmlDoc = new XmlDocument();
    xmlDoc.XmlResolver = new XmlUrlResolver();

    try
    {
        xmlDoc.Load(xmlFilePath);

        // Extract settings from XML
        XmlNodeList settingsList = xmlDoc.SelectNodes("/Settings/Setting");
        foreach (XmlNode settingNode in settingsList)
        {
            string key = settingNode.Attributes["key"].Value;
            string value = settingNode.Attributes["value"].Value;
            configSettings[key] = value;
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine("Error parsing XML file: " + ex.Message);
    }

    return configSettings;
}